// main.go
package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

// healthHandler is a simple health check handler.
// It respects context cancellation/timeouts.
func healthHandler(w http.ResponseWriter, r *http.Request) {
	// Derive a per-request timeout from the incoming context.
	// In a real service you might use a shorter timeout depending on work done.
	ctx, cancel := context.WithTimeout(r.Context(), 2*time.Second)
	defer cancel()

	select {
	case <-ctx.Done():
		// Context was cancelled or timed out before we could respond.
		// This is defensive; in this simple handler we don't actually do
		// long work, but this pattern is reusable.
		err := ctx.Err()
		http.Error(w, "request cancelled: "+err.Error(), http.StatusRequestTimeout)
		return
	default:
		// No blocking operation here; respond immediately.
		// Keeping the pattern explicitly shows correct context usage.
	}

	w.WriteHeader(http.StatusOK)
	_, _ = w.Write([]byte("ok"))
}

func main() {
	// Create a server mux and register handlers.
	mux := http.NewServeMux()
	mux.HandleFunc("/healthz", healthHandler)

	// Create the HTTP server with sensible timeouts.
	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	// Channel that will receive OS signals.
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh,
		syscall.SIGINT,
		syscall.SIGTERM,
	)

	// Channel to signal that the server has shut down.
	shutdownComplete := make(chan struct{})

	// Start the server in a goroutine.
	go func() {
		log.Printf("HTTP server starting on %s", server.Addr)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("HTTP server ListenAndServe: %v", err)
		}
		log.Printf("HTTP server stopped listening")
		close(shutdownComplete)
	}()

	// Block until we receive a termination signal.
	sig := <-sigCh
	log.Printf("Received signal %s, initiating graceful shutdown", sig.String())

	// Create a context with timeout for the graceful shutdown.
	// In production you might want this configurable.
	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	// Trigger graceful shutdown.
	if err := server.Shutdown(shutdownCtx); err != nil {
		log.Printf("HTTP server Shutdown error: %v", err)
		// In case Shutdown times out or fails, force close.
		if closeErr := server.Close(); closeErr != nil {
			log.Printf("HTTP server Close error: %v", closeErr)
		}
	}

	// Wait for the ListenAndServe goroutine to confirm shutdown.
	select {
	case <-shutdownComplete:
		log.Printf("Graceful shutdown complete")
	case <-shutdownCtx.Done():
		// If shutdown context times out, we log and exit anyway.
		log.Printf("Graceful shutdown timed out: %v", shutdownCtx.Err())
	}
}
